import { Head, Html, Main, NextScript } from "next/document";

export default function Document() {
  return (
    <Html lang="en">
      <Head>
        <meta charSet="UTF-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <link rel="icon" type="image/x-icon" href="/Torock.ico" />
        <link rel="shortcut icon" type="image/x-icon" href="/Torock.ico" />
        <link rel="apple-touch-icon" href="/Torock.ico" />
        <script
          dangerouslySetInnerHTML={{
            __html: `(function(){var t=localStorage.getItem('text-size');var s={small:'87.5%',medium:'100%',large:'125%'};document.documentElement.style.fontSize=s[t]||'100%';})();`,
          }}
        />

        <title>ToRock Verse - Anime, Games, Esports, Movie News and Reviews</title>
        <meta
          name="description"
          content="ToRock Verse is your ultimate source for the latest anime, games, esports, films, and pop-culture news. Breaking coverage, reviews, and live scores - all in one place."
        />
        <meta
          name="keywords"
          content="anime news, games news, esports, gaming, culture, film reviews, manga, ToRock Verse, breaking news"
        />
        <meta name="author" content="ToRock Verse" />
        <meta
          name="robots"
          content="index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1"
        />
        <link rel="canonical" href="https://ToRock.verse/" />

        <meta property="og:title" content="ToRock Verse - Anime, Games, Esports, Movie News and Reviews" />
        <meta
          property="og:description"
          content="Your ultimate source for anime, games, esports, films, and pop-culture news. Breaking coverage and live scores."
        />
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://ToRock.verse/" />
        <meta property="og:site_name" content="ToRock Verse" />
        <meta property="og:locale" content="en_US" />

        <meta name="twitter:card" content="summary_large_image" />
        <meta name="twitter:site" content="@ToRockVerse" />
        <meta name="twitter:title" content="ToRock Verse - Anime, Games, Esports, Movie News and Reviews" />
        <meta
          name="twitter:description"
          content="Your ultimate source for anime, games, esports, films, and pop-culture news."
        />

        <link rel="sitemap" type="application/xml" href="/sitemap.xml" />

        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{
            __html: JSON.stringify({
              "@context": "https://schema.org",
              "@type": "NewsMediaOrganization",
              name: "ToRock Verse",
              url: "https://ToRock.verse/",
              description:
                "Your ultimate source for anime, games, esports, films, and pop-culture news.",
              sameAs: [],
              potentialAction: {
                "@type": "SearchAction",
                target: {
                  "@type": "EntryPoint",
                  urlTemplate: "https://ToRock.verse/search?q={search_term_string}",
                },
                "query-input": "required name=search_term_string",
              },
            }),
          }}
        />
      </Head>
      <body>
        <script
          dangerouslySetInnerHTML={{
            __html: `(function(){var s=localStorage.getItem('text-size')||'medium';document.documentElement.classList.add('text-size-'+s);})();`,
          }}
        />
        <Main />
        <NextScript />
      </body>
    </Html>
  );
}
